# bias_audit_data_prep.py — prepares Claude hiring output data for LL144 bias audit

import json
from collections import defaultdict

def compute_impact_ratios(decisions: list[dict]) -> dict:
    """
    decisions: list of {applicant_id, demographic_group, selected: bool}
    Returns selection rates and impact ratios for each demographic group.
    Impact ratio = group selection rate / highest selection rate across all groups.
    LL144 threshold: impact ratio < 0.8 triggers bias finding.
    """
    group_counts = defaultdict(lambda: {"selected": 0, "total": 0})
    for d in decisions:
        g = d["demographic_group"]
        group_counts[g]["total"] += 1
        if d["selected"]:
            group_counts[g]["selected"] += 1

    rates = {g: v["selected"] / v["total"] for g, v in group_counts.items() if v["total"] > 0}
    max_rate = max(rates.values()) if rates else 1

    return {
        "selection_rates": rates,
        "impact_ratios": {g: round(r / max_rate, 4) for g, r in rates.items()},
        "flag_for_audit": [g for g, r in rates.items() if r / max_rate < 0.8],
    }

# incident_reporter.py — tracks AI incidents and enforces reporting deadlines

import json, datetime
from dataclasses import dataclass, field
from typing import Optional

@dataclass
class AIIncident:
    incident_id: str
    description: str
    discovered_at: str          # ISO datetime
    regulation: str             # e.g. "EU-AI-ACT-ART73", "HIPAA-BREACH", "SEC-8K"
    report_deadline_days: int
    recipient: str
    status: str = "open"        # "open" | "reported" | "closed"
    reported_at: Optional[str] = None

    def deadline(self) -> datetime.date:
        discovered = datetime.datetime.fromisoformat(self.discovered_at).date()
        return discovered + datetime.timedelta(days=self.report_deadline_days)

    def days_until_deadline(self) -> int:
        return (self.deadline() - datetime.date.today()).days

    def is_overdue(self) -> bool:
        return self.days_until_deadline() < 0 and self.status != "reported"

def check_incident_deadlines(incidents: list[AIIncident]) -> list[dict]:
    alerts = []
    for inc in incidents:
        days = inc.days_until_deadline()
        if inc.status != "reported":
            alerts.append({
                "incident_id": inc.incident_id,
                "regulation": inc.regulation,
                "days_until_deadline": days,
                "urgency": "overdue" if days < 0 else ("critical" if days <= 2 else "warning"),
                "recipient": inc.recipient,
            })
    return sorted(alerts, key=lambda a: a["days_until_deadline"])
